import React from 'react';
import type { Decorator } from 'storybook/internal/types';

const DEVICES = {
  iphone14: { name: 'iPhone 14', width: 390, height: 844 },
  iphone14ProMax: { name: 'iPhone 14 Pro Max', width: 430, height: 932 },
  pixel7: { name: 'Pixel 7', width: 412, height: 915 },
} as const;

type DeviceKey = keyof typeof DEVICES;

const DEFAULT_DEVICE: DeviceKey = 'iphone14';

const PHONE_FRAME_GLOBAL = 'phoneFrame';

export const PhoneFrameDecorator: Decorator = (Story, context) => {
  const frameEnabled = context.globals[PHONE_FRAME_GLOBAL] !== 'off';
  const deviceKey =
    (context.globals.phoneDevice as DeviceKey) || DEFAULT_DEVICE;
  const device = DEVICES[deviceKey] || DEVICES[DEFAULT_DEVICE];

  if (!frameEnabled) {
    return <Story />;
  }

  return (
    <div
      style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'flex-start',
        padding: 24,
        minHeight: '100%',
        backgroundColor: '#f0f0f0',
      }}
    >
      <div
        style={{
          width: device.width,
          height: device.height,
          borderRadius: 44,
          border: '6px solid #1a1a1a',
          backgroundColor: '#ffffff',
          overflow: 'hidden',
          boxShadow:
            '0 20px 60px rgba(0,0,0,0.3), 0 0 0 2px rgba(0,0,0,0.1)',
          position: 'relative',
          display: 'flex',
          flexDirection: 'column',
        }}
      >
        {/* Notch */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: '50%',
            transform: 'translateX(-50%)',
            width: 126,
            height: 28,
            backgroundColor: '#1a1a1a',
            borderBottomLeftRadius: 18,
            borderBottomRightRadius: 18,
            zIndex: 10,
          }}
        />
        {/* Status bar area */}
        <div style={{ height: 50, flexShrink: 0 }} />
        {/* Content area */}
        <div
          style={{
            flex: 1,
            overflow: 'auto',
          }}
        >
          <Story />
        </div>
        {/* Home indicator */}
        <div
          style={{
            height: 34,
            flexShrink: 0,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
          }}
        >
          <div
            style={{
              width: 134,
              height: 5,
              backgroundColor: '#1a1a1a',
              borderRadius: 3,
            }}
          />
        </div>
      </div>
    </div>
  );
};

export const phoneFrameGlobalTypes = {
  [PHONE_FRAME_GLOBAL]: {
    name: 'Phone Frame',
    description: 'Wrap stories in a phone-shaped frame',
    toolbar: {
      icon: 'mobile',
      title: 'Phone Frame',
      items: [
        { value: 'on', title: 'Frame On', icon: 'mobile' },
        { value: 'off', title: 'Frame Off', icon: 'browser' },
      ],
      dynamicTitle: true,
    },
  },
  phoneDevice: {
    name: 'Device',
    description: 'Select phone device size',
    toolbar: {
      icon: 'grow',
      title: 'Device',
      items: Object.entries(DEVICES).map(([key, device]) => ({
        value: key,
        title: `${device.name} (${device.width}×${device.height})`,
      })),
      dynamicTitle: true,
    },
  },
};

export const phoneFrameInitialGlobals = {
  [PHONE_FRAME_GLOBAL]: 'on',
  phoneDevice: DEFAULT_DEVICE,
};

